"""Crime evidence (#1825) — physical evidence objects generated by crime-tagged deeds.

A crime-tagged deed with a scene leaves ``CrimeEvidence`` at the scene of the crime.
The perpetrator (or anyone) at the scene can **gather** it (Skulduggery check → a real
inventory item), then **dispose** of it (destroying the discovery trail — future heat
from deed-knowledge spread is dampened) or pervert it through a frame-job project
(``world.justice.frame_jobs``). All magnitudes PLACEHOLDER.
"""

from django.test import TestCase

from evennia_extensions.factories import RoomProfileFactory
from world.areas.constants import AreaLevel
from world.areas.factories import AreaFactory
from world.character_sheets.factories import CharacterSheetFactory
from world.checks.test_helpers import force_check_outcome
from world.justice.constants import DEFAULT_HEAT_WEIGHT, EvidenceState
from world.justice.evidence import (
    EvidenceError,
    dispose_evidence,
    gather_evidence,
)
from world.justice.factories import AreaLawFactory, CrimeKindFactory
from world.justice.models import CrimeEvidence, PersonaHeat
from world.justice.services import accrue_for_deed_knowledge, tag_deed_crimes
from world.justice.tests.utils import set_character_location
from world.scenes.factories import SceneFactory
from world.seeds.checks import seed_check_resolution_tables
from world.seeds.security_checks import seed_security_check_content
from world.societies.factories import LegendEntryFactory, SocietyFactory
from world.traits.factories import CheckOutcomeFactory


class EvidenceGenerationTests(TestCase):
    """tag_deed_crimes leaves evidence at the scene of the crime."""

    @classmethod
    def setUpTestData(cls):
        cls.crime = CrimeKindFactory(slug="theft", name="Theft")
        cls.room = RoomProfileFactory()
        cls.scene = SceneFactory(location=cls.room.objectdb)

    def test_tagging_a_scened_deed_generates_evidence_at_the_scene(self):
        deed = LegendEntryFactory(scene=self.scene)
        tag_deed_crimes(deed, [self.crime])
        evidence = CrimeEvidence.objects.get(deed=deed)
        assert evidence.room_profile == self.room
        assert evidence.state == EvidenceState.AT_SCENE
        assert evidence.item_instance is None

    def test_generation_is_idempotent_per_deed(self):
        deed = LegendEntryFactory(scene=self.scene)
        smuggling = CrimeKindFactory(slug="smuggling", name="Smuggling")
        tag_deed_crimes(deed, [self.crime])
        tag_deed_crimes(deed, [smuggling])
        assert CrimeEvidence.objects.filter(deed=deed).count() == 1

    def test_sceneless_deed_generates_no_evidence(self):
        deed = LegendEntryFactory(scene=None)
        tag_deed_crimes(deed, [self.crime])
        assert not CrimeEvidence.objects.filter(deed=deed).exists()

    def test_locationless_scene_generates_no_evidence(self):
        deed = LegendEntryFactory(scene=SceneFactory(location=None))
        tag_deed_crimes(deed, [self.crime])
        assert not CrimeEvidence.objects.filter(deed=deed).exists()


class EvidenceCheckFixture(TestCase):
    """Shared setup: a seeded check pipeline, a room, and a character standing in it."""

    @classmethod
    def setUpTestData(cls):
        seed_check_resolution_tables()
        seed_security_check_content()
        cls.success = CheckOutcomeFactory(name="ev_success", success_level=1)
        cls.failure = CheckOutcomeFactory(name="ev_failure", success_level=-1)
        cls.room = RoomProfileFactory()
        cls.scene = SceneFactory(location=cls.room.objectdb)
        cls.sheet = CharacterSheetFactory()
        cls.character = set_character_location(cls.sheet.character, cls.room.objectdb)
        cls.crime = CrimeKindFactory(slug="theft", name="Theft")
        deed = LegendEntryFactory(scene=cls.scene)
        tag_deed_crimes(deed, [cls.crime])
        cls.deed = deed

    def _evidence(self) -> CrimeEvidence:
        return CrimeEvidence.objects.get(deed=self.deed)


class GatherEvidenceTests(EvidenceCheckFixture):
    def test_successful_gather_claims_a_real_item(self):
        evidence = self._evidence()
        with force_check_outcome(self.success) as capture:
            result = gather_evidence(self.character, evidence)
        assert result.success
        assert capture.target_difficulty == evidence.quality
        evidence = self._evidence()
        assert evidence.state == EvidenceState.GATHERED
        assert evidence.item_instance is not None
        assert evidence.item_instance.holder_character_sheet == self.sheet
        assert evidence.item_instance.game_object is not None
        assert evidence.item_instance.game_object.location == self.character

    def test_failed_gather_leaves_evidence_at_scene(self):
        evidence = self._evidence()
        with force_check_outcome(self.failure):
            result = gather_evidence(self.character, evidence)
        assert not result.success
        evidence = self._evidence()
        assert evidence.state == EvidenceState.AT_SCENE
        assert evidence.item_instance is None

    def test_gather_requires_standing_at_the_scene(self):
        elsewhere = RoomProfileFactory()
        set_character_location(self.character, elsewhere.objectdb)
        with self.assertRaises(EvidenceError):
            gather_evidence(self.character, self._evidence())

    def test_gather_requires_at_scene_state(self):
        evidence = self._evidence()
        with force_check_outcome(self.success):
            gather_evidence(self.character, evidence)
        with self.assertRaises(EvidenceError):
            gather_evidence(self.character, self._evidence())


class DisposeEvidenceTests(EvidenceCheckFixture):
    def _gathered(self) -> CrimeEvidence:
        with force_check_outcome(self.success):
            gather_evidence(self.character, self._evidence())
        return self._evidence()

    def test_successful_dispose_destroys_the_item(self):
        from world.items.models import ItemInstance

        evidence = self._gathered()
        item_pk = evidence.item_instance.pk
        with force_check_outcome(self.success):
            result = dispose_evidence(self.character, evidence)
        assert result.success
        evidence = self._evidence()
        assert evidence.state == EvidenceState.DISPOSED
        assert evidence.item_instance is None
        assert not ItemInstance.objects.filter(pk=item_pk).exists()

    def test_failed_dispose_keeps_the_item(self):
        evidence = self._gathered()
        with force_check_outcome(self.failure):
            result = dispose_evidence(self.character, evidence)
        assert not result.success
        evidence = self._evidence()
        assert evidence.state == EvidenceState.GATHERED
        assert evidence.item_instance is not None

    def test_dispose_requires_holding_the_evidence(self):
        evidence = self._gathered()
        thief_sheet = CharacterSheetFactory()
        with self.assertRaises(EvidenceError):
            dispose_evidence(thief_sheet.character, evidence)


class DisposedHeatDampenerTests(TestCase):
    """All evidence disposed → deed-knowledge heat accrual is dampened."""

    @classmethod
    def setUpTestData(cls):
        cls.crown = SocietyFactory()
        cls.kingdom = AreaFactory(level=AreaLevel.KINGDOM, dominant_society=cls.crown)
        cls.crime = CrimeKindFactory(slug="theft", name="Theft")
        AreaLawFactory(area=cls.kingdom, crime_kind=cls.crime, heat_weight=DEFAULT_HEAT_WEIGHT)
        cls.room = RoomProfileFactory(area=cls.kingdom)
        cls.scene = SceneFactory(location=cls.room.objectdb)

    def _tagged_deed(self):
        deed = LegendEntryFactory(scene=self.scene)
        tag_deed_crimes(deed, [self.crime])
        return deed

    def test_intact_evidence_accrues_full_heat(self):
        deed = self._tagged_deed()
        accrue_for_deed_knowledge(deed=deed, room=self.room.objectdb, new_knower_count=4)
        row = PersonaHeat.objects.get(persona=deed.persona)
        assert row.value == DEFAULT_HEAT_WEIGHT * 4

    def test_all_evidence_disposed_dampens_heat(self):
        deed = self._tagged_deed()
        # Instance-level save (not queryset .update()) — CrimeEvidence is identity-mapped.
        evidence = CrimeEvidence.objects.get(deed=deed)
        evidence.state = EvidenceState.DISPOSED
        evidence.save(update_fields=["state"])
        accrue_for_deed_knowledge(deed=deed, room=self.room.objectdb, new_knower_count=4)
        row = PersonaHeat.objects.get(persona=deed.persona)
        # PLACEHOLDER factor 25%: scale 4 → 1.
        assert row.value == DEFAULT_HEAT_WEIGHT * 1
